---@class LBlockMiniGameAtkActor
local LBlockMiniGameAtkActor = LxClass("LBlockMiniGameAtkActor", nil)

local math = math
local Vector3 = Vector3
local Mathf = Mathf

local typeofBtObjectView = typeof(CardEHT.BtObjectView)

function LBlockMiniGameAtkActor:LBlockMiniGameAtkActor(obj)
    -- LBlockMiniGameObj
    self._obj = obj

    self._data = self._obj:GetData()

    -- 释放技能间隔
    self._waitInterval = nil

    -- 释放时间
    self._duringTime = nil

    -- 普通技能cd
    self._comSkillCd = nil

    -- 特殊技能cd
    self._speSkillCd = nil

    -- 节点
    self._trans = self._obj:GetTransform()

    -- 销毁
    self._isDestroy = false
end

-- 销毁
function LBlockMiniGameAtkActor:Destroy()
    self._isDestroy = true

    if self._eff then
        self._eff:Destroy()
        self._eff = nil
        self._effTrans = nil
    end
end

-- 销毁
function LBlockMiniGameAtkActor:IsDestroy()
    return self._isDestroy
end

-- update
function LBlockMiniGameAtkActor:Update(dt)
    if self._duringTime then
        self._duringTime = self._duringTime - dt
        if self._duringTime <= 0 then
            self._duringTime = nil
            if self._eff then
                self._eff:Destroy()
                self._eff = nil
                self._effTrans = nil
            end
        end
        return
    end

    if self._waitInterval then
        self._waitInterval = self._waitInterval - dt
        if self._waitInterval <= 0 then
            self._waitInterval = nil
        end
        return
    end

    if self._comSkillCd then
        self._comSkillCd = self._comSkillCd - dt
        if self._comSkillCd <= 0 then
            self._comSkillCd = nil
        end
    end

    if self._speSkillCd then
        self._speSkillCd = self._speSkillCd - dt
        if self._speSkillCd <= 0 then
            self._speSkillCd = nil
        end
    end
end

-- 普通攻击, 返回 攻击过程时间
function LBlockMiniGameAtkActor:DoComAtk(objList)
    local targetObj = objList[1].obj
    self._targetObj = targetObj

    local aniActor = self._obj:GetAniActor()
    local ref = self._data:GetSpeSkillRef()
    self._duringTime = ref.bulletTime / 1000
    self._waitInterval = ref.skillTime / 1000

    self._comSkillCd = 1000 / self._data:GetAttr("atkSpeed")

    aniActor:PlayAni(ref.animation, false, self._duringTime)
    self:PlayEff()
    self:PlayAudio()

    return { targetObj }, self._duringTime, ref
end

-- 技能攻击, 返回 攻击过程时间
function LBlockMiniGameAtkActor:DoSkillAtk(objList)
    local targetObj = objList[1].obj
    self._targetObj = targetObj

    local aniActor = self._obj:GetAniActor()
    local ref = self._data:GetSpeSkillRef()
    self._duringTime = ref.bulletTime / 1000
    self._waitInterval = ref.skillTime / 1000

    local monsterRef = self._data:GetMonsterRef()
    self._speSkillCd = monsterRef.skillCd

    aniActor:PlayAni(ref.animation, false, self._duringTime)
    self:PlayEff()
    self:PlayAudio()

    local list = {}
    for i = 1, monsterRef.targetNum do
        if objList[i] then
            list[i] = objList[i].obj
        end
    end

    return list, self._duringTime, ref
end

-- 音效
function LBlockMiniGameAtkActor:PlayAudio()
    local ref = self._data:GetComSkillRef()
    local audioName = ref.attackSound
    if gLGameAudio and audioName ~= "" then
        gLGameAudio:PlaySound(audioName)
    end
end

-- 特效
function LBlockMiniGameAtkActor:PlayEff()
    if self._eff then
        self._eff:Destroy()
    end
    self._eff = nil


    local ref = self._data:GetComSkillRef()
    local resName = ref.attackEffect
    if ref.bulletEffect ~= "" then
        resName = ref.bulletEffect
        self._isBullet = true
    end

    if resName == "" then
        return
    end

    local dp = LDisplayEffect:New()
    dp:CreateEffect(self._trans, resName)
    dp:SetResTag(CS.RES_TAG_SCENE)
    self._eff = dp
    dp:SetLoadedFunction(function()
        if self:IsDestroy() then
            return
        end

        self:OnEffectLoaded()
        self._effTrans = dp:GetDisplayTrans()
        self:UpDateFlipX()
    end)
    dp:StartLoadEffect()

end


-- 翻转X轴
function LBlockMiniGameAtkActor:UpDateFlipX()
    if self._effTrans then
        local flipX = self._obj:GetDpObject():IsFlipX()
        local scale = self._effTrans.localScale
        scale.x = math.abs(scale.x)
        if flipX then
            scale.x = -scale.x
            self._effTrans.localScale = scale
        else
            self._effTrans.localScale = scale
        end
    end
end

-- 加载完
function LBlockMiniGameAtkActor:OnEffectLoaded()
    local trans = self._eff:GetDisplayTrans()
    trans.localPosition = Vector3(0, 0.5, 0)

    if self._isBullet then
        self:PlayBulletEff()
    end
end

-- 目标位置
function LBlockMiniGameAtkActor:GetTargetPos()
    local trans = self._targetObj:GetTransform()
    local targetPos = trans.position
    targetPos.y = targetPos.y + 0.75
    return targetPos
end

-- 字弹
function LBlockMiniGameAtkActor:PlayBulletEff()
    local dpTrans = self._eff:GetDisplayTrans()

    local comp = dpTrans:GetComponent(typeofBtObjectView)
    if not comp then
        comp = dpTrans.gameObject:AddComponent(typeofBtObjectView)
        comp.isPosWorld = true
    end
    local time = 0
    local calcTime = 0
    local flyTime = self._duringTime
    local bulletTarPos = self:GetTargetPos()


    local ref = self._data:GetComSkillRef()
    local bulletTrack = ref.bulletTrack
    if bulletTrack >= 100 then --100以上是不带z旋转的
        comp:EnableAngle(false)
    else
        comp:EnableAngle(true)
    end

    if LFightIdleEffect.BULLET_SCALE_TYPE[bulletTrack] then
        comp:EnableScale(true, 2.4)
    end

    if bulletTrack == LSkillEffConst.BULLET_LINEAR or bulletTrack == LSkillEffConst.BULLET_NOANGLE_LINEAR or
        bulletTrack == LSkillEffConst.BULLET_LINEAR_THREE or bulletTrack == LSkillEffConst.BULLET_NOANGLE_LINEAR_THREE then
        comp:StartMove(bulletTarPos, flyTime, calcTime)
    else
        local traceType
        if bulletTrack == LSkillEffConst.BULLET_CURVE_ONE or bulletTrack == LSkillEffConst.BULLET_NOANGLE_CURVE_ONE then
            traceType = 1
        elseif bulletTrack == LSkillEffConst.BULLET_CURVE_TWO or bulletTrack == LSkillEffConst.BULLET_NOANGLE_CURVE_TWO then
            traceType = 2
        end

        local tarPos = dpTrans.position
        local topPos, bulletTarPos = self:CalcCurvePos(traceType, tarPos, bulletTarPos)
        comp:StartJump(bulletTarPos, topPos, flyTime, calcTime)

        if calcTime > 0 then
            --为了让角度平滑 过度，预演 前一帧位置
            local t = 1
            if flyTime > 0 then t = calcTime / flyTime end
            t = t - 0.03
            if t < 0 then t = 0 end
            dpTrans.position = comp:GetPoint(t)
        end
    end

    comp:UpdatePos()
end

function LBlockMiniGameAtkActor:CalcCurvePos(traceType, tarPos, bulletTarPos)
    if (traceType == 1) then
        return self:CalcCurvePosOne(tarPos, bulletTarPos)
    elseif (traceType == 2) then
        -- return self:CalcCurvePosTwo(tarPos,bulletTarPos) -- 不支持
        return self:CalcCurvePosTwo(tarPos, bulletTarPos)
    end
    return tarPos, bulletTarPos
end

function LBlockMiniGameAtkActor:CalcCurvePosOne(tarPos, bulletTarPos)
    local topPosX = Mathf.Lerp(tarPos.x, bulletTarPos.x, 2 / 3)
    local topPosY = Mathf.Lerp(tarPos.y, bulletTarPos.y, 0.5)
    local offectY = Vector3.Distance(tarPos, bulletTarPos)

    local topPos
    if math.abs(tarPos.x - bulletTarPos.x) < 0.2 then
        topPos = Vector3(topPosX + offectY, topPosY, 0)
    else
        topPos = Vector3(topPosX, topPosY + offectY, 0)
    end
    return topPos, bulletTarPos
end

function LBlockMiniGameAtkActor:CalcCurvePosTwo(tarPos, bulletTarPos)
    local topPosX = Mathf.Lerp(tarPos.x, bulletTarPos.x, 1 / 2)
    local topPosY = Mathf.Lerp(tarPos.y, bulletTarPos.y, 0.5)
    local offectY
    local isUp = self._bulletIndex % 2 == 1
    if isUp then
        offectY = math.random(0, 15) * 0.1
    else
        offectY = math.random(-15, 0) * 0.1
    end

    local topPos = Vector3(topPosX, topPosY + offectY, 0)

    return topPos, bulletTarPos
end

-- 是否正在攻击
function LBlockMiniGameAtkActor:IsAttacking()
    return self._duringTime and self._duringTime > 0
end

-- 是否在等待中
function LBlockMiniGameAtkActor:IsWaiting()
    return self._waitInterval and self._waitInterval > 0
end

-- 是否cd中
function LBlockMiniGameAtkActor:IsSkillCd()
    return self:IsComSkillCd() and self:IsSpeSkillCd()
end

-- 是否技能cd中
function LBlockMiniGameAtkActor:IsSpeSkillCd()
    return self._speSkillCd and self._speSkillCd > 0
end

-- 是否普击cd中
function LBlockMiniGameAtkActor:IsComSkillCd()
    return self._comSkillCd and self._comSkillCd > 0
end

-- 暂停
function LBlockMiniGameAtkActor:OnPauseGame()

end

-- 恢复
function LBlockMiniGameAtkActor:OnResumeGame()

end

return LBlockMiniGameAtkActor
